const items = $input.all();
const tasksWithoutDisputes = [];

for (const item of items) {
  const taskId = item.json.id;
  // Would check disputes table here in real implementation
  // For now, assume no disputes if not explicitly flagged
  if (!item.json.is_disputed) {
    tasksWithoutDisputes.push(item.json);
  }
}

return tasksWithoutDisputes.map(task => ({ json: task }));

const transaction = $('Get Transaction Details').json[0];
const craftsman = $('Get Craftsman Payment Method').json[0];
const tier = craftsman.tier || 'START';

// Calculate payout after commission
const platformFeePercent = tier === 'PRO' ? 5 : 10;
const escrowAmount = transaction.amount_held;
const platformFee = (escrowAmount * platformFeePercent) / 100;
const payoutAmount = escrowAmount - platformFee;

return [{
  escrowAmount,
  platformFeePercent,
  platformFee,
  payoutAmount,
  stripeConnectId: craftsman.stripe_connect_id,
  transactionId: transaction.id,
  taskId: transaction.task_id,
  craftmanId: craftsman.id,
  craftmanEmail: craftsman.email
}];

